// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  var cntr20Cnt = 0;
  var cntr40Cnt = 0;
  if (ds_OnRequest.getRowCount() == 0) return;
  if (ds_OnRequest.getCellData(0, 'admitClsCd') != 'P') {
    if (!(await $c.gus.cfValidate($p, [tb_data3]))) return;
  }

  /* if (ds_ImportOnRequest.isUpdated==false){
      await $c.gus.cfAlertMsg(MSG_CM_ERR_001,["수입 상차 요청 승인"]); //변경된 정보가 없습니다.
      return;
  } */

  if ((ds_OnRequest.getCellData(0, "lineCd") == "WHL" || ds_OnRequest.getCellData(0, "lineCd") == "IAL") && ds_OnRequest.getCellData(0, "lane") != "KSI" && ds_OnRequest.getCellData(0, 'admitClsCd') != 'R' && ds_OnRequest.getCellData(0, 'admitClsCd') != 'E') {
    await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_011);
  }
  if (ds_OnRequest.getCellData(0, 'admitClsCd') == 'O') {
    if (ds_OnRequest.getCellData(0, "odrNo") == "") {
      await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_004);
      return;
    }
  }
  //라인코드가 SITC이고, ODR_CTRL_CLS_CD = 3 인경우에 체선일자 체크
  if (ds_OnRequest.getCellData(0, "lineCd") == "SITC" && ds_OnRequest.getCellData(0, "odrCtrlClsCd") == "3") {
    var sysDate = $c.date.getServerDateTime($p, "yyyyMMdd");
    var demDate = ica_demDt.getValue();
    //시스템 날짜와 체선일자를 비교하여 작거나 같을경우에만 저장가능
    if (parseInt(demDate) < parseInt(sysDate)) {
      await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_012);
      ica_demDt.focus();
      return;
    }
  }

  //라인코드가 TSL이면 상차예정일, 반납지, 반납예정기한일에 빈값이 없는지 체크한다.
  //if (ds_OnRequest.getCellData(0, "lineCd") == "TSL" || ds_OnRequest.getCellData(0, "lineCd") == "EAS") { // 김아름 2011.11.23
  for (var i = 0; i < ds_ImportOnRequest.getRowCount(); i++) {
    //취소한건은 검사되지 않도록함
    // if (ds_ImportOnRequest.RowStatus(i) > 0) {
    if (ds_ImportOnRequest.getRowStatus(i) != "R") {
      if (ds_ImportOnRequest.getCellData(i, "onIntendDt") == "" || (await $c.gus.cfIsNull($p, ds_ImportOnRequest.getCellData(i, "onIntendDt")))) {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_018, ["상차예정일"]);
        return false;
      }
      if (ds_ImportOnRequest.getCellData(i, "rtrnWrkPlNm") == "" || (await $c.gus.cfIsNull($p, ds_ImportOnRequest.getCellData(i, "rtrnWrkPlNm")))) {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["반납지"]);
        return false;
      }
      if (ds_ImportOnRequest.getCellData(i, "rtrnIntendPrdDt") == "" || (await $c.gus.cfIsNull($p, ds_ImportOnRequest.getCellData(i, "rtrnIntendPrdDt")))) {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_018, ["반납예정기한일"]);
        return false;
      }
    }

    //요청수량 체크(이미 승인한 데이타)
    if (ds_ImportOnRequest.getCellData(i, "selfPrgsStsClsCd") == "W") {
      if (ds_ImportOnRequest.getCellData(i, "nrm").substring(0, 2) == "20") {
        cntr20Cnt++;
      }
      if (ds_ImportOnRequest.getCellData(i, "nrm").substring(0, 2) == "40" || ds_ImportOnRequest.getCellData(i, "nrm").substring(0, 2) == "45") {
        cntr40Cnt++;
      }
    }
    // if (ds_ImportOnRequest.getRowStatus(i) ==3){
    if (ds_ImportOnRequest.getRowStatus(i) == "U") {
      ds_ImportOnRequest.setCellData(i, 'admitClsCd', ds_OnRequest.getCellData(0, 'admitClsCd'));
      if (ds_ImportOnRequest.getCellData(i, 'onIntendDt') != '' || ds_ImportOnRequest.getCellData(i, 'rtrnWrkPlNm') != '' || ds_ImportOnRequest.getCellData(i, 'rtrnIntendPrdDt') != '') {
        if (ds_ImportOnRequest.getCellData(i, 'onIntendDt') == '') {
          await $c.win.alert($p, '상차예정일을 입력하세요.');
          return;
        }
        if (ds_ImportOnRequest.getCellData(i, 'rtrnWrkPlNm') == '') {
          await $c.win.alert($p, '반납지를 입력하세요.');
          return;
        }
        if (ds_ImportOnRequest.getCellData(i, 'rtrnIntendPrdDt') == '') {
          await $c.win.alert($p, '반납예정 기한일을 입력하세요.');
          return;
        }
      }
      if (ica_demDt.getValue().length > 0) {
        //체선일(ica_demDt.getValue())이 null 아닌 경우만 Check
        if (ds_ImportOnRequest.getCellData(i, 'onIntendDt') > ica_demDt.getValue()) {
          ds_ImportOnRequest.setRowPosition(i);
          await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_005, ["체선일자", "상차예정일"]);
          return;
        }
        if (ds_ImportOnRequest.getCellData(i, 'onIntendDt') > ds_ImportOnRequest.getCellData(i, 'rtrnIntendPrdDt')) {
          ds_ImportOnRequest.setRowPosition(i);
          await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_005, ["반납예정 기한일", "상차예정일"]);
          return;
        }
      } else {
        if (ds_ImportOnRequest.getCellData(i, 'onIntendDt') > ds_ImportOnRequest.getCellData(i, 'rtrnIntendPrdDt')) {
          ds_ImportOnRequest.setRowPosition(i);
          await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_005, ["반납예정 기한일", "상차예정일"]);
          return;
        }
      }
      if (acb_admitClsCd.getValue() == 'C' || acb_admitClsCd.getValue() == 'O') {
        if (ds_ImportOnRequest.getCellData(i, "selfPrgsStsClsCd") == 'W') {
          ds_ImportOnRequest.setCellData(i, "gubun", '2');
        }
      }
      //요청수량 체크(승인할 데이타)
      if (ds_ImportOnRequest.getCellData(i, "nrm").substring(0, 2) == "20" && ds_ImportOnRequest.getCellData(i, "selfPrgsStsClsCd") != "W") {
        cntr20Cnt++;
      }
      if ((ds_ImportOnRequest.getCellData(i, "nrm").substring(0, 2) == "40" || ds_ImportOnRequest.getCellData(i, "nrm").substring(0, 2) == "45") && ds_ImportOnRequest.getCellData(i, "selfPrgsStsClsCd") != "W") {
        cntr40Cnt++;
      }
    }
    // if (ds_ImportOnRequest.getRowStatus(i) ==3 || ds_ImportOnRequest.getRowStatus(i) ==1){
    if (ds_ImportOnRequest.getRowStatus(i) == "U" || ds_ImportOnRequest.getRowStatus(i) == "C") {
      if (ds_OnRequest.getCellData(0, "demDt") != "") {
        if (ds_OnRequest.getCellData(0, "demDt") < ds_ImportOnRequest.getCellData(i, "onIntendDt")) {
          ds_ImportOnRequest.setRowPosition(i);
          await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_005, ["체선일자", "상차예정일"]);
          return;
        }
      }
    }
  }
  //}

  //승인구분이 오류(E)이면  넘어감. 2009.01.21
  //pcy
  if (acb_admitClsCd.getValue() != 'E' && ds_OnRequest.getCellData(0, "lineCd") != "TSL" && ds_OnRequest.getCellData(0, "lineCd") != "EAS" && ds_OnRequest.getCellData(0, "lineCd") != "SKR" && ds_OnRequest.getCellData(0, "lineCd") != "NOLS" && ds_OnRequest.getCellData(0, "lineCd") != "TCLC" && ds_OnRequest.getCellData(0, "lineCd") != "SOFC" && ds_OnRequest.getCellData(0, "lineCd") != "TMSC" //2014.09.22 TMSC라인 추가
  && ds_OnRequest.getCellData(0, "lineCd") != "SITC" && ds_OnRequest.getCellData(0, "lineCd") != "COH" //2014.11.20 COH 라인추가
  && ds_OnRequest.getCellData(0, "lineCd") != "YNK" //2015.05.15 YNK 라인추가
  && ds_OnRequest.getCellData(0, "lineCd") != "TJM" //2015.05.20 TJM 라인추가
  && ds_OnRequest.getCellData(0, "lineCd") != "MAS" //2016.02.04 MAS 라인추가
  && ds_OnRequest.getCellData(0, "lineCd") != "JJS" //2016.04.11 JJS 라인추가
  && ds_OnRequest.getCellData(0, "lineCd") != "APL" //2016.05.30 APL 라인추가
  && ds_OnRequest.getCellData(0, "lineCd") != "DWH" //2016.08.17 DWH 라인추가
  && ds_OnRequest.getCellData(0, "lineCd") != "COS" //2017.02.01 COS 라인추가
  && ds_OnRequest.getCellData(0, "lineCd") != "MOL" //2017.03.23 MOL 라인추가
  && ds_OnRequest.getCellData(0, "lineCd") != "RHT" //2017.04.05 RHT 라인추가
  && ds_OnRequest.getCellData(0, "lineCd") != "ONE" //2018.03.07 ONE 라인추가
  && ds_OnRequest.getCellData(0, "lineCd") != "SWIL") {
    if (cntr20Cnt > ds_OnRequest.getCellData(0, "cntF20")) {
      await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_010);
      return false;
    }

    // if (cntr40Cnt > ds_OnRequest.getCellData(0, "cntF40") ){
    //     await $c.win.alert(ds_OnRequest.getCellData(0, "cntF40"));
    //     await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_010);
    //     return false;
    // }
  }

  // if (ds_OnRequest.IsUpdated){
  if (ds_OnRequest.getModifiedIndex().length > 0) {
    ds_OnRequest.setCellData(0, 'gubun', 'ImportOnRequest');
    if ((await $c.gus.cfGetByteLength($p, txt_errEtcRsn.getValue())) > 100) {
      await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_006);
      return;
    }
  }

  // Error Code Check
  // ds_chkErrorCd.DataId = "/cm.zz.RetrieveComboCMD.do?sysCd=OnRequestAdmissionEBC&queryId=retrievechkErrorCd"
  //                       + "&param1=" + ds_ImportOnRequest.getCellData(ds_ImportOnRequest.getRowPosition(),'selfTransClntNo')
  //                       + "&param2=" + ds_ImportOnRequest.getCellData(ds_ImportOnRequest.getRowPosition(), 'onReqNo');
  // ds_chkErrorCd.Reset();
  ds_searchChkErrorCd.set("sysCd", "OnRequestAdmissionEBC");
  ds_searchChkErrorCd.set("queryId", "retrievechkErrorCd");
  ds_searchChkErrorCd.set("param1", ds_ImportOnRequest.getCellData(ds_ImportOnRequest.getRowPosition(), 'selfTransClntNo'));
  ds_searchChkErrorCd.set("param2", ds_ImportOnRequest.getCellData(ds_ImportOnRequest.getRowPosition(), 'onReqNo'));
  var result = await $c.sbm.execute($p, sbm_chkErrorCd);
  ds_OnRequest.setCellData(0, "selfTransClntNm", ds_OnRequest.getCellData(0, "selfTransClntNm") + " ");
  if (!(await $c.win.confirm($p, MSG_CM_CRM_001))) return;

  //for(i=1;i<=ds_ImportOnRequest.getRowCount();i++){
  //ds_ImportOnRequest.getCellData(i, "chkFlg", "T";
  //}

  if (acb_admitClsCd2.getValue() == "Y") {
    ds_OnRequest.setCellData(0, "prebilgYn", 1);
  } else if (acb_admitClsCd2.getValue() == "N") {
    ds_OnRequest.setCellData(0, "prebilgYn", 0);
  }

  //await $c.win.alert("kkk1::"+acb_admitClsCd2.getValue()+"::2::"+(ds_OnRequest.getCellData(0, "prebilgYn")));
  if (await $c.gus.cfIsNull($p, ds_OnRequest.getCellData(0, "odrNo"))) {
    if (ds_OnRequest.getCellData(0, "lineCd") == "TSL" && (await $c.gus.cfIsNull($p, acb_admitClsCd2.getValue()))) {
      //await $c.win.alert("kkk2:::"+ds_OnRequest.getCellData(0, "prebilgYn"));
      await $c.win.alert($p, "TSL라인 수입상차요청 승인시에는 반드시 선수납 대상 여부를 기재해야 합니다.");
      return false;
    }
    /*
    if (ds_OnRequest.getCellData(0, "lineCd") == "EAS"
       &&  await $c.gus.cfIsNull(acb_admitClsCd2.getValue())){
        //await $c.win.alert("kkk2:::"+ds_OnRequest.getCellData(0, "prebilgYn"));
        await $c.win.alert("EAS라인 수입상차요청 승인시에는 반드시 선수납 대상 여부를 기재해야 합니다.");
        return false;
    }
    */
    if (ds_OnRequest.getCellData(0, "lineCd") == "SKR" && (await $c.gus.cfIsNull($p, acb_admitClsCd2.getValue()))) {
      //await $c.win.alert("kkk2:::"+ds_OnRequest.getCellData(0, "prebilgYn"));
      await $c.win.alert($p, "SKR라인 수입상차요청 승인시에는 반드시 선수납 대상 여부를 기재해야 합니다.");
      return false;
    }
  } else {
    //await $c.win.alert("기존에 저장된 오더는 그냥 통과");
    //return false;
  }

  //PCY
  if (txt_vsslNm.getValue() != "") {
    txt_vsslNm.setValue(ds_OnRequest.getCellData(0, "vsslCd"));
    ds_OnRequest.setCellData(0, "vsslCd", ds_OnRequest.getCellData(0, "vsslNm"));
  }
  var statusCnt = 0;
  var attachData = udc_attachFile.getData();
  for (var i = 0; i < attachData.length; i++) {
    if (attachData[i].rowStatus != "R") {
      statusCnt++;
    }
  }
  if (statusCnt > 0) {
    scwin.f_Submit();
  } else {
    $c.sbm.execute($p, sbm_saveImportOnRequest);
  }
};

