//-------------------------------------------------------------------------
// TEXT BOX 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUpText = function (inObj, codeObj, disGubun) {
  var pCode = "";
  var pName = "";

  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.  //inObj.getValue().trim() == "" ||
  if (inObj.getReadOnly() || inObj.getValue() == ds_hidden.set("hid_srchSelfTransCoNm")) return;
  if (codeObj != null) {
    if (codeObj.tagName == "OBJECT") {
      codeObj.setValue("");
    } else {
      codeObj.setValue("");
      ds_hidden.set("hid_srchSelfTransCoCd", "");
    }
  }
  pName = inObj.getValue();
  scwin.f_openCommonPopUp(disGubun, pCode, pName, 'T', 'T');
};

//-------------------------------------------------------------------------
// EMEDIT 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUpEmEdit = function (inObj, chkObj, txtObj, disGubun) {
  var pCode = "";
  var pName = "";

  // 해당 EMEDIT가 Disable 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (inObj.ReadOnly || !inObj.Enable || inObj.getValue() == chkObj.getValue()) return;
  if (txtObj != null) {
    txtObj.setValue("");
    txtObj.hidVal = "";
  }
  pCode = inObj.getValue().replace(/^\s*/, '');

  // 값이 입력이 안된 경우  팝업을 실행하지 않음.
  if (pCode == "" || pCode == null) {
    inObj.setValue("");
    chkObj.setValue("");
    return;
  }
  scwin.f_openCommonPopUp(disGubun, pCode, pName, 'T', 'T');
};

