scwin.f_chkDate = async function (row, colid) {
  if (colid == 'onIntendDt' || colid == 'rtrnIntendPrdDt') {
    if (ica_demDt.getValue().length > 0) {
      //체선일(ica_demDt.getValue())이 null 아닌 경우만 Check
      if (ds_ImportOnRequest.getCellData(row, 'onIntendDt') > ica_demDt.getValue()) {
        await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_005, ["체선일자", "상차예정일"]);
        ds_ImportOnRequest.setCellData(row, 'onIntendDt', "");
        return false;
      }
      if (ds_ImportOnRequest.getCellData(row, 'onIntendDt') == "" || ds_ImportOnRequest.getCellData(row, 'rtrnIntendPrdDt') == "") return;
      if (ds_ImportOnRequest.getCellData(row, 'onIntendDt') > ds_ImportOnRequest.getCellData(row, 'rtrnIntendPrdDt')) {
        await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_005, ["반납예정 기한일", "상차예정일"]);
        ds_ImportOnRequest.setCellData(row, 'rtrnIntendPrdDt', "");
        return false;
      }
    } else {
      if (ds_ImportOnRequest.getCellData(row, 'onIntendDt') == "" || ds_ImportOnRequest.getCellData(row, 'rtrnIntendPrdDt') == "") return;
      if (ds_ImportOnRequest.getCellData(row, 'onIntendDt') > ds_ImportOnRequest.getCellData(row, 'rtrnIntendPrdDt')) {
        await $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_005, ["반납예정 기한일", "상차예정일"]);
        ds_ImportOnRequest.setCellData(row, 'rtrnIntendPrdDt', "");
        return false;
      }
    }
  }
};
